word = input()

is_all_uppercase = True
for char in word:
    if ord(char) < 65 or ord(char) > 90:
        is_all_uppercase = False
        break

is_all_lowercase = True
for char in word:
    if ord(char) < 97 or ord(char) > 122:
        is_all_lowercase = False
        break

is_capitalized = False
if ord(word[0]) >= 65 and ord(word[0]) <= 90:
    is_capitalized = True
    for char in word[1:]:
        if ord(char) < 97 or ord(char) > 122:
            is_capitalized = False
            break

if is_all_uppercase or is_all_lowercase or is_capitalized:
    print("true")
else:
    print("false")
